/**
 * Emits per-rule `.jinja` files for the render pipeline (feature 011).
 *
 * The YAML template format (`templates directory`) was retired in favor of
 * per-rule `.jinja` files — see ADR-0013 / spec 011 for design notes.
 * This file owns the two functions that drive that emission:
 *
 *   - `emitJinjaTemplates(config)` — pure function: walks the NodeMap,
 *     asks each node for its `.renderTemplate()` Jinja body, returns
 *     a Map keyed by rule kind (values include the `@generated` header).
 *   - `writeJinjaTemplates(emitted, outputDir)` — writes the Map to
 *     disk and removes any stale `.jinja` files whose rule kinds are
 *     no longer present.
 *
 * All template generation now happens inside the `AssembledNode`
 * class hierarchy in `compiler/node-map.ts`. Each `renderTemplate()`
 * method returns Jinja-shaped output directly — clause / variant
 * inlining, `$VAR` → `{{ var }}` translation, and separator-filter
 * selection are all collapsed into that one chokepoint.
 *
 * These emitted files are the canonical authored templates under
 * `packages/{lang}/templates/`. The native Askama copies under
 * `rust/crates/sittir-{lang}/templates/` are derived later by
 * `cli.ts` from this source of truth; never edit those copies by hand.
 */

import * as fs from 'node:fs';
import { join } from 'node:path';
import type { NodeMap } from '../compiler/types.ts';
import { AssembledGroup } from '../compiler/node-map.ts';
import type {
	AssembledBranch,
	AssembledMulti,
	AssembledNode,
	AssembledPolymorph
} from '../compiler/node-map.ts';
import type { Rule } from '../compiler/rule.ts';
import { compileWordMatcher } from '../compiler/common.ts';
import type { CodegenEmitter } from './emitter.ts';
import { classifyTemplateEmission } from './shared.ts';

export interface EmitTemplatesConfig {
	grammar: string;
	nodeMap: NodeMap;
	grammarSha?: string;
}

export interface EmittedTemplates {
	bodies: Map<string, string>;
}

interface EmitCtx {
	readonly nodeMap: NodeMap;
	readonly wordMatcher: RegExp;
	readonly externals: readonly string[];
	readonly rules: Record<string, Rule>;
}

// Nunjucks whitespace control (`{#- ... -#}`) strips whitespace
// flanking the comment — crucial when a template is rendered as a
// nested child, where the outer `.trim()` doesn't apply. Without the
// trim, every nested render picks up a leading `\n` from the line
// break between this header and the body. See core/render.ts for the
// top-level `.trim()` that handles the outermost render.
const GENERATED_HEADER =
	'{#- @generated by @sittir/codegen — do not edit. Source: packages/codegen/src/emitters/templates.ts -#}';

export class TemplateEmitter implements CodegenEmitter<EmittedTemplates> {
	readonly #config: EmitTemplatesConfig;
	readonly #wordMatcher: RegExp;
	#bodies = new Map<string, string>();

	constructor(config: EmitTemplatesConfig) {
		this.#config = config;
		this.#wordMatcher = compileWordMatcher(config.nodeMap.word, config.nodeMap.rules ?? {}) ?? /\w/;
	}

	emitLeaf(node: AssembledNode): void {
		this.#emitNode(node);
	}

	emitBranch(node: AssembledNode): void {
		this.#emitNode(node);
	}

	emitPolymorph(node: AssembledNode): void {
		this.#emitNode(node);
	}

	emitGroup(node: AssembledNode): void {
		this.#emitNode(node);
	}

	finalize(): EmittedTemplates {
		return { bodies: new Map(this.#bodies) };
	}

	#emitNode(node: AssembledNode): void {
		const body = emitBodyForNode(
			node,
			this.#config.nodeMap.rules ?? {},
			this.#wordMatcher,
			this.#config.nodeMap.externals
		);
		if (body === null) return;
		this.#bodies.set(node.kind, `${GENERATED_HEADER}\n${body}`);
	}
}

function emitOne(node: AssembledNode, ctx: EmitCtx): string | undefined {
	switch (node.modelType) {
		case 'branch':
			return emitBranchTemplate(node, ctx);
		case 'polymorph':
			return emitPolymorphTemplate(node, ctx);
		case 'group':
			return emitGroupTemplate(node, ctx);
		case 'multi':
			return emitMultiTemplate(node, ctx);
		case 'supertype':
		case 'pattern':
		case 'keyword':
		case 'token':
		case 'enum':
			return undefined;
		default: {
			const _exhaustive: never = node;
			throw new Error(`emitOne: unhandled modelType ${(_exhaustive as AssembledNode).modelType}`);
		}
	}
}

// Stubs — Task 2.4 fills these in:
function emitBranchTemplate(_n: AssembledBranch, _ctx: EmitCtx): string {
	return '';
}

function emitPolymorphTemplate(_n: AssembledPolymorph, _ctx: EmitCtx): string {
	return '';
}

function emitGroupTemplate(_n: AssembledGroup, _ctx: EmitCtx): string {
	return '';
}

function emitMultiTemplate(_n: AssembledMulti, _ctx: EmitCtx): string {
	return '';
}

/**
 * Emit one `.jinja` body per rule in the NodeMap. Returns a Map keyed
 * by rule kind; values are the full file contents (including the
 * `@generated` comment header).
 *
 * Rules without a template (leaves / keywords / tokens / supertypes /
 * enums / non-polymorph-form groups / multis) are skipped — the
 * renderer's fallback handles them.
 */
export function emitJinjaTemplates(config: EmitTemplatesConfig): EmittedTemplates {
	const { nodeMap } = config;
	const wordMatcher = compileWordMatcher(nodeMap.word, nodeMap.rules ?? {});
	const bodies = new Map<string, string>();
	for (const node of nodeMap.nodes.values()) {
		const emission = classifyTemplateEmission(node);
		if (emission !== 'emit') continue;
		let body: string | null;
		try {
			body = emitBodyForNode(node, nodeMap.rules ?? {}, wordMatcher ?? /\w/, nodeMap.externals);
		} catch (err) {
			// Re-throw with grammar + kind context so the emitter caller
			// gets an actionable error message. `{ cause }` preserves
			// the original stack for Error.cause-aware debuggers (Node
			// 16.9+), matching the renderNunjucks wrap in core/render.ts.
			const detail = err instanceof Error ? err.message : String(err);
			throw new Error(`emitJinjaTemplates: failed on ${config.grammar}/${node.kind}: ${detail}`, {
				cause: err
			});
		}
		if (body === null) continue;
		// Canonical-hidden architecture (Option Y): templates are emitted
		// at the kind's actual name. Hidden alias-source kinds (`_x`) get
		// `_x.jinja`; visible kinds (`x`) get `x.jinja`. The runtime
		// canonicalizes parser-output `$type` (visible alias target →
		// hidden alias source) inside `wrapNode` BEFORE template lookup,
		// and `render.ts` falls back to `_${$type}.jinja` when called
		// with a visible $type that has no own template. So both producer
		// paths (factory output stamping `_x` directly + parser output
		// remapped by wrap) converge on the single hidden template file.
		bodies.set(node.kind, `${GENERATED_HEADER}\n${body}`);
	}
	return { bodies };
}

/**
 * Write per-kind `.jinja` files to `outputDir`. Creates the directory
 * if it does not exist. After writing, scans the directory for any
 * `.jinja` files whose kind is not in `emitted` and removes them —
 * prevents stale files from accumulating across regenerations when a
 * rule is renamed or removed from the grammar.
 *
 * Preserves `.gitkeep` and non-`.jinja` files (README.md, etc.).
 */
/**
 * Ask the node for its Jinja body. Returns `null` for node kinds that
 * don't own a template file (leaves, keywords, tokens, supertypes,
 * enums, multis, non-polymorph-form groups). The class-hierarchy base
 * `renderTemplate()` returns `undefined` for those — we translate that
 * signal to the emitter's `null`.
 */
function emitBodyForNode(
	node: AssembledNode,
	rules: Record<string, Rule>,
	wordMatcher: RegExp,
	externals: ReadonlySet<string> | undefined
): string | null {
	if (
		node.modelType === 'pattern' ||
		node.modelType === 'keyword' ||
		node.modelType === 'token' ||
		node.modelType === 'supertype' ||
		node.modelType === 'enum' ||
		node.modelType === 'multi'
	) {
		return null;
	}
	if (node instanceof AssembledGroup && !node.parentKind && !node.userFacing) {
		// Non-polymorph-form groups without an alias-source reference
		// are hidden helpers inlined at their referrers; no file emitted.
		//
		// Groups that ARE userFacing (populated by `markUserFacing` when
		// the hidden kind shows up as an alias source in some other
		// rule's child/field slots) get their own template — tree-sitter
		// emits them via `alias($._kind, $.visible)` and the render
		// pipeline dispatches to the hidden rule's body. Covers
		// variant() adoption on rules with field-bearing branches
		// (`_update_expression_postfix` etc.), where the hoisted hidden
		// rule gets wrapped as a GroupRule by classifyHiddenSeqRule even
		// though it's an alias source — the group classification fits
		// the shape but the inlining assumption doesn't.
		return null;
	}
	const entry = node.renderTemplate(rules, wordMatcher, externals);
	if (!entry) return null;
	const template = entry.template;
	if (typeof template !== 'string') {
		throw new Error(
			`emitBodyForNode: rule '${node.kind}' (${node.modelType}) produced no template string — ` +
				`renderTemplate() returned ${JSON.stringify(entry)}`
		);
	}
	return template;
}

export function writeJinjaTemplates(emitted: EmittedTemplates, outputDir: string): void {
	fs.mkdirSync(outputDir, { recursive: true });
	for (const [kind, body] of emitted.bodies) {
		fs.writeFileSync(join(outputDir, `${kind}.jinja`), body, 'utf-8');
	}
	// Stale-file cleanup — only touches `.jinja` files. Anything else
	// (`.gitkeep`, README) is left alone. A pre-existing `_meta.json`
	// from the short-lived sidecar era (prior to the joinby-filter
	// migration) is removed — the Jinja bodies carry every separator
	// now, so the sidecar is dead data.
	const existing = fs.readdirSync(outputDir);
	const legacyMeta = join(outputDir, '_meta.json');
	if (fs.existsSync(legacyMeta)) fs.rmSync(legacyMeta, { force: true });
	for (const name of existing) {
		if (!name.endsWith('.jinja')) continue;
		const kind = name.slice(0, -'.jinja'.length);
		if (!emitted.bodies.has(kind)) {
			fs.rmSync(join(outputDir, name), { force: true });
		}
	}
}
